+    #[test]
+    fn test_prepared_direct_simple_insert_learns_runtime_record_header_for_small_rows() {
+        let conn = Connection::open(":memory:").unwrap();
+        conn.execute(
+            "CREATE TABLE prep_direct_record_header (id INTEGER PRIMARY KEY, name TEXT, score INTEGER);",
+        )
+        .unwrap();
+        let stmt = conn
+            .prepare("INSERT INTO prep_direct_record_header VALUES (?1, ('name_' || ?1), (?1 * 7))")
+            .unwrap();
+
+        let direct = stmt
+            .precompiled_dml()
+            .and_then(|dispatch| dispatch.direct_simple_insert.as_ref())
+            .expect("benchmark-shaped INSERT should stay on the direct insert lane");
+        assert!(
+            direct.cached_record_header.borrow().is_none(),
+            "runtime record-header cache should start empty before the first execution"
+        );
+
+        assert_eq!(
+            conn.execute_prepared_with_params(&stmt, &[SqliteValue::Integer(1)])
+                .unwrap(),
+            1
+        );
+        assert!(
+            direct.cached_record_header.borrow().is_some(),
+            "first small-row execution should teach the direct insert lane a reusable record header"
+        );
+
+        assert_eq!(
+            conn.execute_prepared_with_params(&stmt, &[SqliteValue::Integer(2)])
+                .unwrap(),
+            1
+        );
+    }
